import{c as a,Z as r,Q as o,j as n,o as i,m as l}from"./chunks/framework.qjzPVSkb.js";const g=JSON.parse('{"title":"上下文窗口","description":"模型单次对话中能\\"记住\\"的最大 Token 数量，决定 AI 的短期记忆上限","frontmatter":{"title":"上下文窗口","description":"模型单次对话中能\\"记住\\"的最大 Token 数量，决定 AI 的短期记忆上限","difficulty":"beginner"},"headers":[],"relativePath":"terms/context-window.md","filePath":"terms/context-window.md"}'),d={name:"terms/context-window.md"};function s(h,t,c,p,u,m){const e=r("DifficultyBadge");return o(),n("div",null,[i(e,{level:"beginner"}),t[0]||(t[0]=l('<h1 id="上下文窗口" tabindex="-1">上下文窗口 <a class="header-anchor" href="#上下文窗口" aria-label="Permalink to &quot;上下文窗口&quot;">​</a></h1><p>上下文窗口（Context Window）决定了 AI 模型在一次对话中<strong>能同时&quot;看到&quot;多少信息</strong>。它是衡量模型实际可用能力的关键指标之一。</p><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>上下文窗口是 LLM 单次处理的最大 Token 数量——包括你输入的所有内容、历史对话、以及模型即将输出的内容。超过这个限制，模型就会&quot;忘记&quot;最早的信息。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>想象你在<strong>一张桌子上办公</strong>：</p><ul><li><strong>上下文窗口</strong> = 桌子的大小</li><li><strong>你的对话历史</strong> = 桌上的文件</li><li><strong>新问题</strong> = 你要处理的新文件</li></ul><p>桌子越大（上下文窗口越大），你能同时铺开的文件就越多（对话历史能保留更多）。一旦文件多到放不下，你必须把最早的文件收起来（模型忘记早期信息）。</p><p>不同模型桌子大小差异极大：</p><table tabindex="0"><thead><tr><th>模型</th><th>上下文窗口</th></tr></thead><tbody><tr><td>GPT-3.5（初版）</td><td>4K Token（一张小课桌）</td></tr><tr><td>GPT-4</td><td>8K~128K</td></tr><tr><td>Claude 3.5 Sonnet</td><td>200K（一整张会议桌）</td></tr><tr><td>Gemini 1.5 Pro</td><td>1M+（一整间教室的地板）</td></tr></tbody></table><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>上下文窗口的大小由模型架构（特别是位置编码方式）决定。在 Transformer 中，自注意力机制的计算复杂度随序列长度<strong>平方增长</strong>（O(n²)），因此扩大上下文窗口需要大量工程优化。</p><p>实际应用中需要注意：并不是上下文窗口越大就越好。更大的窗口意味着<strong>更慢的响应速度、更高的 API 成本</strong>，而且模型在超长上下文末尾的&quot;注意力&quot;往往会衰减。</p><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/token.html">Token</a> —— 上下文窗口的计数单位</li><li><a href="/ai-knowledge/terms/prompt.html">Prompt</a> —— 每次对话消耗上下文窗口容量</li></ul><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="https://docs.anthropic.com/en/docs/build-with-claude/context-windows" target="_blank" rel="noreferrer">Anthropic: 上下文窗口详解</a></li><li><a href="https://arxiv.org/abs/2307.03172" target="_blank" rel="noreferrer">Lost in the Middle</a> —— 论文：长上下文中模型容易忽略中间信息</li></ul>',17))])}const _=a(d,[["render",s]]);export{g as __pageData,_ as default};
